import { HTTPFacilitatorClient } from '@x402/core/http';
import { withBazaar } from '@x402/extensions/bazaar';

const BAZAAR_URL = process.env.BAZAAR_URL || 'https://bazaar.x402.org';
const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';

/**
 * Build a Bazaar-extended facilitator client for discovery queries.
 */
export function createBazaarClient() {
  const facilitator = new HTTPFacilitatorClient({ url: BAZAAR_URL });
  return withBazaar(facilitator);
}

async function registerEndpoint(resource) {
  const response = await fetch(`${BAZAAR_URL}/discovery/resources`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(resource),
  });

  if (!response.ok) {
    const text = await response.text().catch(() => response.statusText);
    throw new Error(`Bazaar registration failed (${response.status}): ${text}`);
  }

  return response.json();
}

/**
 * Register the POST /skills/generate endpoint on x402 Bazaar.
 * Non-blocking — caller should catch errors and log warnings.
 */
export function registerGenerateEndpoint() {
  return registerEndpoint({
    url: `${BASE_URL}/skills/generate`,
    description: 'Generate an Agent Skill for a smart contract on Base Mainnet ($0.10 USDC)',
    input: {
      type: 'http',
      method: 'POST',
